const body = $input.item.json.body || $input.item.json;
const data = body.data || {};
const msg = data.message || {};
const key = data.key || {};

if (body.event !== 'messages.upsert' || key.fromMe === true) return [];

const phone = (key.remoteJid || '').replace('@s.whatsapp.net', '').replace('@lid', '');
if (!phone) return [];

let text = msg.conversation || '';
if (!text && msg.extendedTextMessage) text = msg.extendedTextMessage.text || '';
if (!text && msg.imageMessage) text = msg.imageMessage.caption || '';
if (!text && msg.listResponseMessage && msg.listResponseMessage.singleSelectReply) text = msg.listResponseMessage.singleSelectReply.selectedRowId || '';
if (!text && msg.buttonsResponseMessage) text = msg.buttonsResponseMessage.selectedButtonId || '';
text = text.trim();

const hasLoc = !!(msg.locationMessage);
const hasImg = !!(msg.imageMessage);

let mode = 'menu';
if (hasImg && (hasLoc || text)) mode = 'rapido';
else if (text.match(/^RPT-\d{4}-\d{5}$/i)) mode = 'protocolo';
else if (/^([1-9]|1[0-2])$/.test(text)) mode = 'categoria';
else if (/^(sim|s)$/i.test(text)) mode = 'confirmar';

return {
  phone, pushName: data.pushName || 'Cidadao', text, mode,
  msgId: key.id || '', remoteJid: key.remoteJid || '',
  hasImage: hasImg,
  imageUrl: hasImg ? (msg.imageMessage.mediaUrl || msg.imageMessage.url || '') : '',
  imageCaption: hasImg ? (msg.imageMessage.caption || '') : '',
  hasLocation: hasLoc,
  latitude: hasLoc ? msg.locationMessage.degreesLatitude : null,
  longitude: hasLoc ? msg.locationMessage.degreesLongitude : null,
  locationAddress: hasLoc ? (msg.locationMessage.address || '') : ''
};

const d = $input.item.json;
const EVO = ($env.EVOLUTION_BASE_URL || 'http://localhost:8080') + '/message/sendText/' + ($env.EVOLUTION_INSTANCE || 'reporteai');
const API = $env.SPRING_BOOT_URL || 'http://localhost:8081';
const KEY = $env.EVOLUTION_API_KEY || '';

let step = 'send'; let url = EVO; let method = 'POST';
let headers = { apikey: KEY, 'Content-Type': 'application/json' };
let bodyObj = {};

if (d.mode === 'menu') {
  bodyObj = { number: d.phone, text: '\ud83c\udfd9\ufe0f *Reporte AI*\n\nOla, ' + d.pushName + '!\n\n1 Reportar problema\n2 Modo rapido (foto+local)\n3 Consultar protocolo\n4 Ajuda\n\nResponda com o numero.', delay: 1500 };
} else if (d.mode === 'categoria') {
  bodyObj = { number: d.phone, text: '*Categoria do problema?*\n\n1 Lixo\n2 Iluminacao\n3 Buracos\n4 Agua/Esgoto\n5 Vegetacao\n6 Transito\n7 Seguranca\n8 Animais\n9 Poluicao\n10 Acessibilidade\n11 Turismo\n12 Outros\n\nResponda com o numero.', delay: 1500 };
} else if (d.mode === 'confirmar') {
  bodyObj = { number: d.phone, text: '\u2705 Confirmado! Processando...', delay: 1000 };
} else if (d.mode === 'protocolo') {
  step = 'consulta'; url = API + '/api/v1/ocorrencias/protocolo/' + encodeURIComponent(d.text);
  method = 'GET'; headers = { 'Content-Type': 'application/json' }; bodyObj = null;
} else if (d.mode === 'rapido') {
  step = 'criar'; url = API + '/api/v1/ocorrencias'; method = 'POST';
  headers = { 'Content-Type': 'application/json' };
  bodyObj = { descricao: d.text || d.imageCaption || 'Problema via foto', latitude: d.latitude, longitude: d.longitude, enderecoTexto: d.locationAddress || null, fotoUrl: d.imageUrl || null, gravidade: 'MEDIA', canal: 'WHATSAPP_RAPIDO', cidadeId: parseInt($env.CIDADE_PADRAO_ID || '1') };
}

return { _step: step, _phone: d.phone, _evoUrl: EVO, _evoKey: KEY, _method: method, _url: url, _headers: headers, _body: bodyObj ? JSON.stringify(bodyObj) : '' };

const prev = $('Preparar Request').first().json;
const resp = $input.item.json;
const step = prev._step;

if (step === 'send') return [];

const phone = prev._phone; let text = '';

if (step === 'consulta') {
  if (resp.protocolo) {
    const e = {RECEBIDA:'\ud83d\udce5',EM_ANALISE:'\ud83d\udd0d',VALIDADA:'\u2705',EM_RESOLUCAO:'\ud83d\udd27',RESOLVIDA:'\ud83c\udf89',ARQUIVADA:'\ud83d\udce6',REJEITADA:'\u274c'};
    const s = (resp.status||'').replace(/_/g,' ');
    const desc = resp.descricao && resp.descricao.length > 80 ? resp.descricao.substring(0,80)+'...' : (resp.descricao||'-');
    text = (e[resp.status]||'') + ' *' + resp.protocolo + '*\n\nStatus: *' + s + '*\nCategoria: ' + (resp.categoriaNome||'-') + '\n' + desc;
  } else { text = '\u26a0\ufe0f Protocolo nao encontrado. Formato: RPT-2026-00001'; }
} else if (step === 'criar') {
  text = '\u2705 *Ocorrencia registrada!*\n\nProtocolo: *' + (resp.protocolo||'N/A') + '*\nCategoria: ' + (resp.categoriaNome||'Classificando...') + '\nPrioridade: ' + (resp.scorePrioridade||'0') + '\n\nObrigado!';
}

return { _url: prev._evoUrl, _key: prev._evoKey, _body: JSON.stringify({number:phone,text:text,delay:1200}) };
